+import java.nio.file.Files;
+import java.nio.file.Path;
+import java.nio.file.Paths;
+import java.util.concurrent.atomic.AtomicBoolean;
+import java.util.stream.Stream;
+
+public class Main {
+    private static final String PN_CONFIGURATION_FQN = "com.pubnub.api.PNConfiguration";
+    private static final String PUBNUB_FQN = "com.pubnub.api.PubNub";
+    private static final String UUID_FACTORY_EXPRESSION = "com.pubnub.api.PubNub.generateUUID()";
+
+    public static void main(String[] args) throws IOException {
+        Path root = args.length > 0 ? Paths.get(args[0]) : Paths.get(".");
+        if (!Files.isDirectory(root)) {
+            throw new IllegalArgumentException("Input path is not a directory: " + root);
+        }
+
+        try (Stream<Path> paths = Files.walk(root)) {
+            paths.filter(path -> Files.isRegularFile(path) && path.toString().endsWith(".java"))
+                .forEach(Main::transformFile);
+        }
+    }
+
+    private static void transformFile(Path file) {
+        try {
+            CompilationUnit cu = StaticJavaParser.parse(file);
+            AtomicBoolean changed = new AtomicBoolean(false);
+
+            cu.findAll(ObjectCreationExpr.class)
+                .forEach(
+                    expr -> {
+                        if (isTargetPnConfigurationCreation(cu, expr) && expr.getArguments().isEmpty()) {
+                            Expression uuidExpr = StaticJavaParser.parseExpression(UUID_FACTORY_EXPRESSION);
+                            expr.setArguments(NodeList.nodeList(uuidExpr));
+                            changed.set(true);
+                        }
+                    });
+
+            if (changed.get()) {
+                Files.writeString(file, cu.toString(), StandardCharsets.UTF_8);
+            }
+        } catch (Exception e) {
+            throw new RuntimeException("Failed to transform " + file, e);
+        }
+    }
+
+    private static boolean isTargetPnConfigurationCreation(CompilationUnit cu, ObjectCreationExpr expr) {
+        String typeName = expr.getType().getNameAsString();
+        String typeString = expr.getType().asString();
+        boolean matchesType = PN_CONFIGURATION_FQN.equals(typeString) || "PNConfiguration".equals(typeName);
+        if (!matchesType) {
+            return false;
+        }
+
+        return hasPubNubApiImport(cu) || PN_CONFIGURATION_FQN.equals(typeString) || expr.getType().isClassOrInterfaceType();
+    }
+
+    private static boolean hasPubNubApiImport(CompilationUnit cu) {
+        return cu.getImports().stream()
+            .anyMatch(
+                imp ->
+                    (!imp.isAsterisk() && PN_CONFIGURATION_FQN.equals(imp.getNameAsString()))
+                        || (!imp.isAsterisk() && PUBNUB_FQN.equals(imp.getNameAsString()))
+                        || (imp.isAsterisk() && "com.pubnub.api".equals(imp.getNameAsString())));
+    }
+}
